import SwiftUI
import UIKit

struct PromoData: Equatable {
    let code: String
    let discount: Int
}

final class UserAccountStore: ObservableObject {
    @Published private(set) var appliedPromo: PromoData?
    @Published private(set) var statusMessage: String = "No promo applied"

    func applyPromo(code: String, discount: Int) {
        let sanitizedCode = code.trimmingCharacters(in: .whitespacesAndNewlines)
        let sanitizedDiscount = max(0, min(discount, 100))
        guard !sanitizedCode.isEmpty else {
            statusMessage = "Invalid promo code"
            return
        }
        appliedPromo = PromoData(code: sanitizedCode, discount: sanitizedDiscount)
        statusMessage = "Applied promo \(sanitizedCode) for \(sanitizedDiscount)% off"
    }
}

final class PromoLinkHandler {
    static let shared = PromoLinkHandler()

    private init() {}

    func parsePromo(from url: URL) -> PromoData? {
        guard let components = URLComponents(url: url, resolvingAgainstBaseURL: false) else {
            return nil
        }

        guard let host = components.host?.lowercased(), host == "myapp.com" else {
            return nil
        }

        let normalizedPath = components.path.trimmingCharacters(in: CharacterSet(charactersIn: "/")).lowercased()
        guard normalizedPath == "promo" else {
            return nil
        }

        let items = components.queryItems ?? []
        let code = items.first(where: { $0.name.lowercased() == "code" })?.value
        let discountString = items.first(where: { $0.name.lowercased() == "discount" })?.value

        guard let code, !code.isEmpty,
              let discountString,
              let discount = Int(discountString) else {
            return nil
        }

        return PromoData(code: code, discount: discount)
    }

    @discardableResult
    func handle(url: URL, accountStore: UserAccountStore) -> Bool {
        guard let promo = parsePromo(from: url) else { return false }
        accountStore.applyPromo(code: promo.code, discount: promo.discount)
        return true
    }
}

final class AppDelegate: NSObject, UIApplicationDelegate {
    func application(_ application: UIApplication,
                     continue userActivity: NSUserActivity,
                     restorationHandler: @escaping ([UIUserActivityRestoring]?) -> Void) -> Bool {
        guard userActivity.activityType == NSUserActivityTypeBrowsingWeb,
              let incomingURL = userActivity.webpageURL else {
            return false
        }

        let store = AppEnvironment.shared.userAccountStore
        return PromoLinkHandler.shared.handle(url: incomingURL, accountStore: store)
    }
}

